const email = $json;
const subject = email.subject || '';
const bodyContent = email.body?.content || '';
const receivedDateTime = email.receivedDateTime || '';

// Strip HTML - preserve newlines so line-anchored regex works
const plainBody = bodyContent
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/p>/gi, '\n')
  .replace(/<[^>]+>/g, '')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>');

// Extract value after the first colon on the numbered line
function extractField(text, fieldNum) {
  const pattern = new RegExp(`^${fieldNum}\\..*?:\\s*(.+)`, 'm');
  const match = text.match(pattern);
  return match ? match[1].trim() : '';
}

const customerName   = extractField(plainBody, 1);
const modelName      = extractField(plainBody, 6);
const endSupplyType  = extractField(plainBody, 8);
const tonerStatusRaw = extractField(plainBody, 9);
const deviceSN       = extractField(plainBody, 12);

// Parse "Black 50%,Yellow 20%,Magenta 20%,Cyan 10%" into individual columns
const tonerLevels = {};
tonerStatusRaw.split(',').forEach(part => {
  const m = part.trim().match(/^(\w+)\s+(\d+)%$/);
  if (m) tonerLevels[m[1]] = parseInt(m[2], 10);
});

return [{
  json: {
    emailId:          email.id,
    receivedDateTime,
    customerName,
    deviceSN,
    modelName,
    endSupplyType,
    tonerStatusRaw,
    tonerBlack:   tonerLevels['Black']   ?? null,
    tonerCyan:    tonerLevels['Cyan']    ?? null,
    tonerMagenta: tonerLevels['Magenta'] ?? null,
    tonerYellow:  tonerLevels['Yellow']  ?? null,
    subject
  }
}];

